# Dockerfile: tini as PID 1 forwards SIGTERM and reaps ffmpeg zombies
FROM node:20-slim
RUN apt-get update \
 && apt-get install -y --no-install-recommends tini ffmpeg \
 && rm -rf /var/lib/apt/lists/*
WORKDIR /app
COPY package.json package-lock.json ./
RUN npm ci --omit=dev && npm cache clean --force
COPY . .
USER node
# tini is PID 1; node is its child but still gets forwarded signals
ENTRYPOINT ["/usr/bin/tini", "--"]
CMD ["node", "worker.js"]

